"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const evidence=[["Usage","18 teams saved a review step"],["Risk","No blocking dependency"],["Owner","Design has signed off"]];
export default function EvidenceWeaveCard(){const [active,setActive]=useState(0);const reduced=useReducedMotion();return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">evidence weave</p><h2 className="mt-1 text-xl font-black text-[#111]">Decision signals</h2><div role="group" aria-label="Evidence signals" className="mt-4 space-y-2">{evidence.map(([name],index)=><motion.button key={name} type="button" aria-pressed={active===index} onClick={()=>setActive(index)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className={active===index?"flex min-h-11 w-full items-center justify-between rounded-xl border-2 border-[#111] bg-[#e6fbff] px-3 text-left text-sm font-bold":"flex min-h-11 w-full items-center justify-between rounded-xl border border-[#ececee] bg-white px-3 text-left text-sm font-bold"}>{name}<motion.i animate={{scale:active===index?1:0.6}} className="h-2.5 w-2.5 rounded-full bg-[#38bdf8]"/></motion.button>)}</div><motion.p key={active} initial={{opacity:0,y:4}} animate={{opacity:1,y:0}} transition={{duration:.16}} aria-live="polite" className="mt-4 text-sm text-[#4a4a4f]"><b className="text-[#111]">{evidence[active][0]}:</b> {evidence[active][1]}</motion.p></section>}
